example.code:
RSpec.describe UserService do describe '#create' do let(:params) { { name: 'John', email: 'john@example.com' } }
it 'creates user with valid params' do result = described_class.create(params) expect(result).to be_success end
it 'returns error with missing email' do result = described_class.create(params.except(:email)) expect(result).to be_failure expect(result.error).to eq('email is required') end end end

class UserTest extends TestCase
{
    public function test_user_can_be_created(): void
    {
        $response = $this->postJson('/api/users', [
            'name' => 'John',
            'email' => 'john@example.com',
        ]);
        $response->assertStatus(201);
    }
}

@ExtendWith(MockitoExtension.class)
class UserServiceTest {
    @Mock
    private UserRepository userRepository;

    @InjectMocks
    private UserService userService;

    @Test
    void shouldCreateUser() {
        CreateUserDto dto = new CreateUserDto("John", "john@example.com");
        when(userRepository.save(any())).thenReturn(new User(1L, "John", "john@example.com"));
        User result = userService.createUser(dto);
        assertThat(result.getName()).isEqualTo("John");
    }
}

@SpringBootTest
class UserServiceTest {
    @Autowired
    private UserService userService;

    @Test
    void shouldCreateUser() {
        CreateUserDto dto = new CreateUserDto("John", "john@example.com");
        User result = userService.createUser(dto);
        assertThat(result.getName()).isEqualTo("John");
    }
}

public class UserServiceTests
{
    [Fact]
    public async Task CreateAsync_ShouldReturnUser()
    {
        var mockRepo = new Mock<IUserRepository>();
        mockRepo.Setup(r => r.SaveAsync(It.IsAny<User>()))
                .ReturnsAsync(new User { Name = "John", Email = "john@example.com" });
        var service = new UserService(mockRepo.Object);

        var result = await service.CreateAsync(new CreateUserDto("John", "john@example.com"));

        result.Name.Should().Be("John");
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_create_user() {
        let user = User::new("John", "john@example.com");
        assert_eq!(user.name, "John");
    }

    #[tokio::test]
    async fn test_async_fetch() {
        let result = fetch_data().await;
        assert!(result.is_ok());
    }
}
